import{_ as a}from"./chunks/cloudflare api token截图.cXTahxtC.js";import{_ as l}from"./chunks/查看全局令牌.BhcACLhK.js";import{_ as i,o,c as r,a2 as t}from"./chunks/framework.DnrXFDHb.js";const I=JSON.parse('{"title":"Cloudflare API Token","description":"","frontmatter":{},"headers":[],"relativePath":"ur/Safety/cloudflare-api-token.md","filePath":"ur/Safety/cloudflare-api-token.md","lastUpdated":1781962217000}'),d={name:"ur/Safety/cloudflare-api-token.md"};function n(c,e,s,p,u,h){return o(),r("div",null,[...e[0]||(e[0]=[t('<h1 id="cloudflare-api-token" tabindex="-1">Cloudflare API Token <a class="header-anchor" href="#cloudflare-api-token" aria-label="Permalink to &quot;Cloudflare API Token&quot;">​</a></h1><p>Cloudflare API credentials ImgBed کو file changes کے بعد Cloudflare CDN cache purge کرنے دیتے ہیں۔</p><p><img src="'+a+'" alt="Cloudflare API Token settings" loading="lazy"></p><h2 id="کہاں-configure-کریں" tabindex="-1">کہاں Configure کریں <a class="header-anchor" href="#کہاں-configure-کریں" aria-label="Permalink to &quot;کہاں Configure کریں&quot;">​</a></h2><p>admin panel کھولیں، پھر جائیں:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Security Settings -&gt; Cloudflare API Token</span></span></code></pre></div><p>آپ کو یہ fields بھرنی ہیں:</p><ul><li>Zone ID</li><li>Account email</li><li>API Key</li></ul><h2 id="یہ-setting-کیا-کرتی-ہے" tabindex="-1">یہ Setting کیا کرتی ہے <a class="header-anchor" href="#یہ-setting-کیا-کرتی-ہے" aria-label="Permalink to &quot;یہ Setting کیا کرتی ہے&quot;">​</a></h2><p>Cloudflare public image URLs کو cache کر سکتا ہے۔</p><p>Caching image delivery کو تیز بناتی ہے، لیکن file delete، block، replace، یا move کرنے کے بعد پرانا content کچھ وقت تک دکھ سکتا ہے۔</p><p>Cloudflare API credentials configure ہونے کے بعد ImgBed ان operations کے مکمل ہونے پر متعلقہ Cloudflare cache purge کرنے کی کوشش کرتا ہے۔</p><p>یہ اس وقت مفید ہے جب:</p><ul><li>آپ image delete کریں اور چاہتے ہوں کہ public link جلد از جلد کام کرنا بند کر دے۔</li><li>آپ image block کریں اور چاہتے ہوں کہ visitors original file نہ دیکھ سکیں۔</li><li>آپ same name سے file replace کریں اور چاہتے ہوں کہ visitors نئی version جلد دیکھیں۔</li><li>آپ files move یا rename کریں اور چاہتے ہوں کہ old path cache جلد refresh ہو۔</li><li>آپ public access rules بدلیں اور چاہتے ہوں کہ public gallery یا random image cache جلد update ہو۔</li></ul><h2 id="خالی-چھوڑنے-سے-کیا-ہوگا" tabindex="-1">خالی چھوڑنے سے کیا ہوگا <a class="header-anchor" href="#خالی-چھوڑنے-سے-کیا-ہوگا" aria-label="Permalink to &quot;خالی چھوڑنے سے کیا ہوگا&quot;">​</a></h2><p>اس setting کے بغیر بھی ImgBed normally کام کرتا ہے۔</p><p>فرق صرف یہ ہے کہ ImgBed actively Cloudflare CDN cache purge نہیں کرے گا۔ visitors پرانا content Cloudflare cache کے naturally expire ہونے تک دیکھ سکتے ہیں۔</p><h2 id="zone-id-کیسے-تلاش-کریں" tabindex="-1">Zone ID کیسے تلاش کریں <a class="header-anchor" href="#zone-id-کیسے-تلاش-کریں" aria-label="Permalink to &quot;Zone ID کیسے تلاش کریں&quot;">​</a></h2><p>Zone ID اس site کا Cloudflare Zone ID ہے جو آپ کے ImgBed domain کے لیے استعمال ہوتی ہے۔</p><ol><li>Cloudflare dashboard میں sign in کریں۔</li><li>وہ site کھولیں جس میں آپ کا ImgBed domain شامل ہے۔</li><li>site overview page پر <code>Zone ID</code> تلاش کریں۔</li><li>اسے ImgBed کے <code>Zone ID</code> field میں copy کریں۔</li></ol><p>یہ site Zone ID ہے، account ID نہیں۔</p><h2 id="account-email" tabindex="-1">Account Email <a class="header-anchor" href="#account-email" aria-label="Permalink to &quot;Account Email&quot;">​</a></h2><p>وہ email address درج کریں جس سے آپ Cloudflare میں sign in کرتے ہیں۔</p><p>یہ نیچے دی گئی API Key سے match ہونا چاہیے۔</p><h2 id="api-key" tabindex="-1">API Key <a class="header-anchor" href="#api-key" aria-label="Permalink to &quot;API Key&quot;">​</a></h2><p>اپنی Cloudflare Global API Key درج کریں۔</p><ol><li>Cloudflare dashboard میں sign in کریں۔</li><li>اپنا profile کھولیں۔</li><li>API Tokens page پر جائیں۔</li><li><code>Global API Key</code> تلاش کریں۔</li><li>اسے view اور copy کریں۔</li><li>ImgBed کے <code>API Key</code> field میں paste کریں۔</li></ol><p><img src="'+l+'" alt="View global API key" loading="lazy"></p><h2 id="کب-اثر-کرے-گا" tabindex="-1">کب اثر کرے گا <a class="header-anchor" href="#کب-اثر-کرے-گا" aria-label="Permalink to &quot;کب اثر کرے گا&quot;">​</a></h2><p>fields بھرنے کے بعد settings save کریں۔</p><p>آئندہ file changes خودکار طور پر Cloudflare cache purge کرنے کی کوشش کریں گی۔ پچھلے operations retroactively purge نہیں ہوتے۔ اگر آپ نے setup سے پہلے file delete یا replace کی ہے، تو Cloudflare cache expire ہونے کا انتظار کریں یا Cloudflare میں manual purge کریں۔</p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="کیا-یہ-required-ہے؟" tabindex="-1">کیا یہ Required ہے؟ <a class="header-anchor" href="#کیا-یہ-required-ہے؟" aria-label="Permalink to &quot;کیا یہ Required ہے؟&quot;">​</a></h3><p>نہیں۔</p><p>اگر آپ کا domain Cloudflare استعمال نہیں کرتا، یا CDN cache delay سے مسئلہ نہیں، تو اسے خالی چھوڑ سکتے ہیں۔</p><h3 id="غلط-credentials-uploads-کو-خراب-کریں-گے؟" tabindex="-1">غلط Credentials Uploads کو خراب کریں گے؟ <a class="header-anchor" href="#غلط-credentials-uploads-کو-خراب-کریں-گے؟" aria-label="Permalink to &quot;غلط Credentials Uploads کو خراب کریں گے؟&quot;">​</a></h3><p>عموماً نہیں۔</p><p>غلط credentials صرف ImgBed کو Cloudflare cache purge کرنے سے روکیں گے۔ upload اور normal file access جاری رہنا چاہیے۔</p><h3 id="deleted-image-اب-بھی-کیوں-کھل-رہی-ہے؟" tabindex="-1">Deleted Image اب بھی کیوں کھل رہی ہے؟ <a class="header-anchor" href="#deleted-image-اب-بھی-کیوں-کھل-رہی-ہے؟" aria-label="Permalink to &quot;Deleted Image اب بھی کیوں کھل رہی ہے؟&quot;">​</a></h3><p>سب سے عام وجہ یہ ہے کہ Cloudflare کے پاس پرانی file cached ہے۔</p><p>صحیح Cloudflare API credentials کے ساتھ ImgBed file delete ہونے پر متعلقہ URL cache purge کرتا ہے۔</p><h3 id="file-replace-کرنے-کے-بعد-پرانی-image-کیوں-دکھ-رہی-ہے؟" tabindex="-1">File Replace کرنے کے بعد پرانی Image کیوں دکھ رہی ہے؟ <a class="header-anchor" href="#file-replace-کرنے-کے-بعد-پرانی-image-کیوں-دکھ-رہی-ہے؟" aria-label="Permalink to &quot;File Replace کرنے کے بعد پرانی Image کیوں دکھ رہی ہے؟&quot;">​</a></h3><p>یہ بھی عموماً CDN cache کی وجہ سے ہوتا ہے۔</p><p>یہ setting configured ہونے کے بعد ImgBed same name والی file overwrite ہونے پر old URL cache purge کرنے کی کوشش کرتا ہے۔</p>',44)])])}const b=i(d,[["render",n]]);export{I as __pageData,b as default};
